/// Server configuration for banner display.
#[derive(Debug, Clone)]
pub struct BannerConfig {
    pub version: String,
    pub host: String,
    pub port: u16,
    pub docs_path: Option<String>,
    pub redoc_path: Option<String>,
    pub route_count: usize,
    pub middleware_count: usize,
}

impl Default for BannerConfig {
    fn default() -> Self {
        Self {
            version: env\!("CARGO_PKG_VERSION").to_string(),
            host: "127.0.0.1".to_string(),
            port: 8000,
            docs_path: Some("/docs".to_string()),
            redoc_path: Some("/redoc".to_string()),
            route_count: 0,
            middleware_count: 0,
        }
    }
}

impl BannerConfig {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn version(mut self, v: &str) -> Self {
        self.version = v.to_string();
        self
    }

    pub fn host(mut self, h: &str) -> Self {
        self.host = h.to_string();
        self
    }

    pub fn port(mut self, p: u16) -> Self {
        self.port = p;
        self
    }

    pub fn routes(mut self, count: usize) -> Self {
        self.route_count = count;
        self
    }

    pub fn middleware(mut self, count: usize) -> Self {
        self.middleware_count = count;
        self
    }

    pub fn base_url(&self) -> String {
        format\!("http://{}:{}", self.host, self.port)
    }

    pub fn docs_url(&self) -> Option<String> {
        self.docs_path.as_ref().map(|p| format\!("{}{}", self.base_url(), p))
    }
}

/// Startup banner renderer.
pub struct StartupBanner {
    config: BannerConfig,
}

impl StartupBanner {
    pub fn new(config: BannerConfig) -> Self {
        Self { config }
    }

    /// Render the banner to the given output.
    pub fn render(&self, output: &RichOutput) {
        eprintln\!("[DEBUG] StartupBanner::render() mode={:?}", output.mode());
        match output.mode() {
            OutputMode::Rich => self.render_rich(output),
            OutputMode::Plain | OutputMode::Minimal => self.render_plain(output),
        }
    }

    fn render_plain(&self, output: &RichOutput) {
        output.print(&format\!("fastapi_rust v{}", self.config.version));
        output.print("Runtime: asupersync");
        output.print("Edition: Rust 2024");
        output.print("");
        output.print("Server:");
        output.print(&format\!("  Listening: {}", self.config.base_url()));

        if let Some(docs_url) = self.config.docs_url() {
            output.print(&format\!("  Docs: {}", docs_url));
        }

        output.print(&format\!("  Routes: {} endpoints", self.config.route_count));
        output.print(&format\!("  Middleware: {} layers", self.config.middleware_count));
    }

    #[cfg(feature = "rich")]
    fn render_rich(&self, output: &RichOutput) {
        // In rich mode, use panels and styled text
        output.panel(ASCII_LOGO, Some(&format\!("fastapi_rust v{}", self.config.version)));
        output.rule(Some("Server"));
        output.print(&format\!("  Listening: {}", self.config.base_url()));
        if let Some(docs_url) = self.config.docs_url() {
            output.print(&format\!("  Docs: {}", docs_url));
        }
        output.print(&format\!("  Routes: {} endpoints", self.config.route_count));
    }

    #[cfg(not(feature = "rich"))]
    fn render_rich(&self, output: &RichOutput) {
        self.render_plain(output);
    }

    /// Get plain text representation (for agents/testing).
    pub fn as_plain_text(&self) -> String {
        let mut lines = vec\![];
        lines.push(format\!("fastapi_rust v{}", self.config.version));
        lines.push("Runtime: asupersync".to_string());
        lines.push("Edition: Rust 2024".to_string());
        lines.push(String::new());
        lines.push("Server:".to_string());
        lines.push(format\!("  Listening: {}", self.config.base_url()));
        if let Some(docs_url) = self.config.docs_url() {
            lines.push(format\!("  Docs: {}", docs_url));
        }
        lines.push(format\!("  Routes: {} endpoints", self.config.route_count));
        lines.push(format\!("  Middleware: {} layers", self.config.middleware_count));
        lines.join("\n")
    }
}

/// Convenience function to print startup banner.
pub fn print_startup_banner(config: BannerConfig, output: &RichOutput) {
    eprintln\!("[DEBUG] print_startup_banner() called with {:?}", config);
    StartupBanner::new(config).render(output);
}
